for (let i = 1; i <= 5; i++) {
  console.log("গণনা: " + i);
}

let i = 0;
while (i < 3) {
  console.log("while:", i);
  i++;
}

let j = 0;
do {
  console.log("do-while:", j);
  j++;
} while (j < 3);

const fruits = ["আম", "কাঁঠাল", "লিচু"];
for (const fruit of fruits) {
  console.log(fruit);
}

const person = { name: "করিম", age: 30 };
for (const key in person) {
  console.log(key, "=", person[key]);
}
